$(document).ready(function(){console.log("Galerie je připravena k použití.");$('.galerie-nahled').on('click',function(udalost){udalost.preventDefault();let velkyObrazekUrl=$(this).attr('href');let lightboxHtml=`
            <div id="moje-vyskakovaci-okno" style="position: fixed; top: 0; left: 0; width: 100%; height: 100%; background: rgba(0,0,0,0.8); display: flex; justify-content: center; align-items: center; z-index: 9999; cursor: pointer;">
                <img src="${velkyObrazekUrl}" style="max-width: 90%; max-height: 90%; border: 5px solid white; border-radius: 10px; box-shadow: 0 0 20px rgba(0,0,0,0.5);">
                <span style="position: absolute; top: 20px; right: 40px; color: white; font-size: 50px; font-weight: bold;">&times;</span>
            </div>
            `;$('body').append(lightboxHtml)});$('body').on('click','#moje-vyskakovaci-okno',function(){$(this).remove()});$("#sablona-paticka").load("sablony/paticka.html");$("#sablona-menu").load("sablony/menu.html",function(){let aktualniStranka=window.location.pathname.split('/').pop();if(aktualniStranka==="")aktualniStranka="index.html";$('.nav-link[href="'+aktualniStranka+'"]').addClass('active')})})